/*===================================================================================================================================*/
/*  U4      u4_g_SumU2(const U2 * u2_ap_HALF, const U2 u2_a_NUM_HALF)                                                                */
/* --------------------------------------------------------------------------------------------------------------------------------- */
/*  Arguments:      -                                                                                                                */
/*  Return:         -                                                                                                                */
/*===================================================================================================================================*/
U4      u4_g_SumU2(const U2 * u2_ap_HALF, const U2 u2_a_NUM_HALF)
{
    U4         u4_t_lpcnt;
    U4         u4_t_sum;

    u4_t_sum = (U4)0U;
    for(u4_t_lpcnt = (U4)0U; u4_t_lpcnt < (U4)u2_a_NUM_HALF; u4_t_lpcnt++){
        u4_t_sum += (U4)u2_ap_HALF[u4_t_lpcnt];
    }

    return(u4_t_sum);
}
